from flask import Flask, request, jsonify

app = Flask(__name__)

@app.route("/submit", methods=["POST"])
def submit():
    name = request.form.get("name", "Anonymous")
    email = request.args.get("ref", "direct")
    browser = request.headers.get("User-Agent", "Unknown")
    return jsonify({
        "name": name,
        "referrer": email,
        "browser": browser[:50]
    })
